import{_ as e,a}from"./chunks/频繁报错提示.B4wBXruJ.js";import{_ as d,o as i,c as r,a2 as l}from"./chunks/framework.DnrXFDHb.js";const _=JSON.parse('{"title":"Обмеження частоти завантажень для користувачів","description":"","frontmatter":{},"headers":[],"relativePath":"uk-UA/Safety/user-rate-limits.md","filePath":"uk-UA/Safety/user-rate-limits.md","lastUpdated":1781962217000}'),s={name:"uk-UA/Safety/user-rate-limits.md"};function o(p,t,n,h,c,m){return i(),r("div",null,[...t[0]||(t[0]=[l('<h1 id="обмеження-частоти-завантажень-для-користувачів" tabindex="-1">Обмеження частоти завантажень для користувачів <a class="header-anchor" href="#обмеження-частоти-завантажень-для-користувачів" aria-label="Permalink to &quot;Обмеження частоти завантажень для користувачів&quot;">​</a></h1><p>User rate limits визначають, як часто звичайні користувачі або відвідувачі можуть завантажувати файли з головної сторінки. Це допомагає захистити публічну сторінку завантаження від зловживань.</p><p>Функція впливає лише на завантаження з головної сторінки. Завантаження адміністратора та завантаження через API Tokens не обмежуються user rate limits.</p><h2 id="де-це-налаштовується" tabindex="-1">Де це налаштовується <a class="header-anchor" href="#де-це-налаштовується" aria-label="Permalink to &quot;Де це налаштовується&quot;">​</a></h2><p>Відкрийте адмін-панель і перейдіть до:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>System Settings -&gt; Security Settings -&gt; Upload Management -&gt; User Rate Limits</span></span></code></pre></div><p><img src="'+e+'" alt="Налаштування user rate limit" loading="lazy"></p><h2 id="увімкнення-rate-limits" tabindex="-1">Увімкнення rate limits <a class="header-anchor" href="#увімкнення-rate-limits" aria-label="Permalink to &quot;Увімкнення rate limits&quot;">​</a></h2><p>Після ввімкнення <code>Enable Rate Limits</code> ImgBed відстежує нещодавні завантаження за IP-адресою того, хто завантажує.</p><p>Типові значення:</p><table tabindex="0"><thead><tr><th>Налаштування</th><th>Типово</th><th>Опис</th></tr></thead><tbody><tr><td>Detection window</td><td>1.5 hours</td><td>Наскільки далеко назад рахуються записи завантажень.</td></tr><tr><td>Max file count</td><td>20</td><td>Максимальна кількість файлів у detection window.</td></tr><tr><td>Single file size limit</td><td>20 MB</td><td>Максимальний розмір одного файлу.</td></tr><tr><td>Total upload size limit</td><td>200 MB</td><td>Максимальний загальний розмір завантажень у detection window.</td></tr></tbody></table><p>Наприклад, із вікном 1,5 години, 20 файлами, 20 MB на файл і 200 MB загалом завантаження з тієї самої IP-адреси блокуються, щойно перевищено будь-який із налаштованих лімітів.</p><h2 id="виключення-типів-фаилів" tabindex="-1">Виключення типів файлів <a class="header-anchor" href="#виключення-типів-фаилів" aria-label="Permalink to &quot;Виключення типів файлів&quot;">​</a></h2><p><code>Excluded upload file types</code> блокує звичайним користувачам або відвідувачам завантаження вибраних категорій файлів.</p><p>Доступні категорії:</p><table tabindex="0"><thead><tr><th>Тип</th><th>Опис</th></tr></thead><tbody><tr><td>Images</td><td>jpg, png, webp, gif та подібні файли зображень</td></tr><tr><td>Videos</td><td>mp4, webm, mov та подібні відеофайли</td></tr><tr><td>Audio</td><td>mp3, flac, wav та подібні аудіофайли</td></tr><tr><td>Documents</td><td>pdf, txt, md, docx та подібні документи</td></tr><tr><td>Other</td><td>Файли поза наведеними категоріями, наприклад zip, rar, exe, apk</td></tr></tbody></table><p>Типово категорія не вибрана, тобто вона дозволена.</p><p>Натискання на категорію підсвічує її, а це означає, що цей тип заблоковано.</p><p>Якщо вибрати <code>Other</code>, відвідувачі, які завантажують zip або rar, будуть заблоковані й побачать повідомлення, що цей тип файлу не підтримується.</p><h2 id="повідомлення-про-блокування" tabindex="-1">Повідомлення про блокування <a class="header-anchor" href="#повідомлення-про-блокування" aria-label="Permalink to &quot;Повідомлення про блокування&quot;">​</a></h2><p>Коли спрацьовує ліміт, користувачі бачать відповідне повідомлення:</p><p><img src="'+a+'" alt="Повідомлення про занадто часте завантаження" loading="lazy"></p><table tabindex="0"><thead><tr><th>Сценарій</th><th>Значення повідомлення</th></tr></thead><tbody><tr><td>Один файл завеликий</td><td>Файл завеликий, його варто стиснути перед завантаженням.</td></tr><tr><td>Тип файлу заблоковано</td><td>Цей тип файлу не підтримується. Приберіть його й спробуйте ще раз.</td></tr><tr><td>Завантаження занадто часті</td><td>Нещодавні завантаження занадто часті, показано час повторної спроби.</td></tr><tr><td>Загальний розмір завеликий</td><td>Сумарний розмір нещодавніх завантажень занадто великий, показано час повторної спроби.</td></tr></tbody></table><h2 id="коли-вмикати" tabindex="-1">Коли вмикати <a class="header-anchor" href="#коли-вмикати" aria-label="Permalink to &quot;Коли вмикати&quot;">​</a></h2><p>Увімкніть user rate limits, якщо ваша головна сторінка завантаження доступна публічно.</p><p>Типові причини:</p><ul><li>ви хвилюєтеся щодо масових автоматизованих завантажень;</li><li>хочете обмежити великі завантаження від відвідувачів;</li><li>хочете дозволити звичайним користувачам завантажувати лише зображення, а не архіви чи інсталятори;</li><li>хочете залишити публічне завантаження доступним, але контролювати використання ресурсів.</li></ul><p>Якщо сайт тільки для вас або завантажувати можуть лише адміністратори, це можна залишити вимкненим.</p>',28)])])}const f=d(s,[["render",o]]);export{_ as __pageData,f as default};
